  ('judicial-388a63c0-moex-00019', 'judicial-388a63c0', 'judicial-388a63c0-moex-114-521f6696', 'sub-judicial-388a63c0-06', NULL, 'essay', '債務人甲因不能清償債務而經法院裁定破產，其債權人共有 35位，其中
破產債權人乙之債權新臺幣（下同）520 萬元，經其他債權人丙爭執並
依破產法第 125條提出異議，經法院審酌各項事證後，裁定確認該債權
人乙可加入破產債權之數額為 20 萬元，其餘 500 萬元裁定不准加入破
產債權，法院即以此數額為破產債權之分配。乙不服乃另行對破產管理
人獨立提起民事訴訟，請求確認債權 520 萬元存在並可列入破產債權分
配，破產管理人抗辯本件既已經破產法院裁定確認，即應專以該法院裁
定之數額進行分配，請法院程序駁回之。請問受理訴訟之法院應否許
可？訴訟中該有爭議之金額，破產管理人應如何處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "33fb77e0762a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "106", "s": "0416", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "破產法與消費者債務清理條例", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
